import AppKit

/// The dictat mascot, embedded as a base64 PNG (36×36, transparent background) so it
/// ships inside the app bundle with no separate resource files. Rendered in the menu bar.
enum Mascot {
    /// 18pt menu-bar icon. Not a template image — it keeps its red color.
    static let menuBar: NSImage = {
        let image = NSImage(data: Data(base64Encoded: pngBase64, options: .ignoreUnknownCharacters) ?? Data())
            ?? NSImage()
        image.size = NSSize(width: 18, height: 18)
        image.isTemplate = false
        return image
    }()

    private static let pngBase64 = """

"""
}
